def perceive(data):
    text = data if isinstance(data, str) else str(data)
    out = {}
    for tok in text.replace(",", " ").split():
        if "=" not in tok:
            continue
        key, raw = tok.split("=", 1)
        key = key.strip()
        if key not in ("wind_speed", "demand_mw"):
            continue
        try:
            out[key] = float(raw)
        except ValueError:
            continue
    return out
